export function getTeacherForClass(className: string): string {
  const classNum = className.replace("Class ", "");
  const romanMap: Record<string, string> = {"1":"I","2":"II","3":"III","4":"IV","5":"V","6":"VI","7":"VII","8":"VIII","9":"IX","10":"X"};
  const roman = romanMap[classNum] || classNum;
  const teacher = TEACHERS.find(t => {
    const classes = t.classes.split(",").map(c => c.trim());
    return classes.includes(roman) && t.designation === "Teacher";
  });
  return teacher?.name || "";
}
